__kernel void dynproc_kernel(const int iteration,
                             __global const int *gpuWall,
                             __global int *gpuSrc,
                             __global int *gpuDst,
                             const int cols,
                             const int rows,
                             const int startStep,
                             const int borderCols,
                             const int HALO,
                             __local int *prev,
                             __local int *result,
                             __global int *outputBuffer)
{
    (void)rows;
    (void)borderCols;
    (void)HALO;
    (void)prev;
    (void)result;
    (void)outputBuffer;

    if (get_group_id(0) != 0)
        return;

    const int lid = (int)get_local_id(0);
    const int lsize = (int)get_local_size(0);

    for (int i = 0; i < iteration; i++) {
        const int wallOffset = (startStep + i) * cols;

        for (int x = lid; x < cols; x += lsize) {
            int min_val = gpuSrc[x];

            if (x > 0) {
                int left = gpuSrc[x - 1];
                if (left < min_val) min_val = left;
            }

            if (x < cols - 1) {
                int right = gpuSrc[x + 1];
                if (right < min_val) min_val = right;
            }

            gpuDst[x] = gpuWall[wallOffset + x] + min_val;
        }

        barrier(CLK_GLOBAL_MEM_FENCE);

        if (i != iteration - 1) {
            __global int *tmp = gpuSrc;
            gpuSrc = gpuDst;
            gpuDst = tmp;
        }
    }

    if ((iteration & 1) == 0) {
        for (int x = lid; x < cols; x += lsize) {
            gpuDst[x] = gpuSrc[x];
        }
    }
}
